/// The kernel's boot and initialization process is managed by OSTD.
/// After the process is done, the kernel's execution environment
/// (e.g., stack, heap, tasks) will be ready for use and the entry function
/// labeled as `#[ostd::main]` will be called.
#[ostd::main]
pub fn main() {
    let _main_span = trace_span!("kernel_main", stage = "initialization").entered();

    info!("开始执行内核主函数");
    debug!("追踪系统已初始化");

    spawn(async {
        vfs::init_vfs().await;
        for type_ in TYPE_MAP {
            println!("#### OS COMP TEST GROUP START basic-{} ####", type_);
            for task in TASKS {
                println!("Testing {} :", task);
                let (_, handle) = ThreadBuilder::new().path(&format!("/{}/basic/{}", type_, task)).spawn().await.unwrap();
                handle.await.inspect_err(|e| {
                    warn!("ThreadBuilder::spawn 失败: {:?}", e);
                });
            }
            println!("#### OS COMP TEST GROUP END basic-{} ####", type_);
            //  println!("#### OS COMP TEST GROUP START interrupts-{} ####", type_);
            //  for interrupt in INTERRUPTS {
            //      let (_, handle) = ThreadBuilder::new().path(&format!("/{}/{}", type_, interrupt)).spawn().await.unwrap();
            //      handle.await.inspect_err(|e| {
            //         warn!("ThreadBuilder::spawn 失败: {:?}", e);
            //     });
            //  }

            // println!("#### OS COMP TEST GROUP END interrupts-{} ####", type_);

            // println!("#### OS COMP TEST GROUP START splice-{} ####", type_);

            // // 顺序运行 5 组用例：./test_splice 1..5
            // for case_id in 1..=5 {
            //     let argv = vec![
            //         CString::new("test_splice").unwrap(),
            //         CString::new(format!("{}", case_id)).unwrap(),
            //     ];
            //     let path = format!("/{}/test_splice", type_);
            //     let (_, handle) = ThreadBuilder::new()
            //         .path(&path)
            //         .argv(argv)
            //         .spawn()
            //         .await
            //         .unwrap();
            //     handle.await.inspect_err(|e| {
            //         warn!("ThreadBuilder::spawn 失败: {:?}", e);
            //     });
            // }
            // println!("#### OS COMP TEST GROUP END splice-{} ####", type_);


            // println!("#### OS COMP TEST GROUP START copyfilerange-{} ####", type_);
            // for test in COPY_FILE_RANGE_TESTS {
            //     let (_, handle) = ThreadBuilder::new().path(&format!("/{}/{}", type_, test)).spawn().await.unwrap();
            //     handle.await.inspect_err(|e| {
            //     warn!("ThreadBuilder::spawn 失败: {:?}", e);
            // });
            // }
            // println!("#### OS COMP TEST GROUP END copyfilerange-{} ####", type_);
        }
        ostd::task::scheduler::stop_running();
    }, None);

    info!("内核主函数完成设置，BSP 进入空闲循环");

    debug!("注册 AP 入口函数");
    ostd::boot::smp::register_ap_entry(ap_main);

    let cpus = CpuSet::new_full();
    inter_processor_call(&cpus, || {
        let cpu_id = disable_preempt().current_cpu().as_usize();
        info!(cpu_id, "CPU 运行 inter_processor_call");
    });

    let mut core = ostd::task::scheduler::Core::new();
    core.run();
    exit_qemu(QemuExitCode::Success);
}

fn ap_main() -> ! {
    let cpu_id;
    {
        let disable_preempt: ostd::task::DisabledPreemptGuard = disable_preempt();
        cpu_id = disable_preempt.current_cpu().as_usize();
        info!(cpu_id, "AP 进入 ap_main 函数，准备进入空闲循环");
    }

    let mut core = ostd::task::scheduler::Core::new();
    core.run();
    unreachable!()
}

