pub async fn do_brk(state: &mut ThreadState, context: &mut ostd::cpu::UserContext) -> Result<ControlFlow<i32, Option<isize>>>  {
    let [new_brk, ..] = context.syscall_arguments();

    let new_heap_end = if new_brk == 0 {
        None
    } else {
        Some(new_brk as usize)
    };

    debug!("new heap end = {:x?}", new_brk);

    let new_heap_end = state
        .process_vm
        .heap
        .brk(new_heap_end, state.process_vm.root_vmar())
        .await?;

    Ok(ControlFlow::Continue(Some(new_heap_end as isize)))
}

//! clone  — 按 CLONE_THREAD 分治创建“线程”或“进程”。


use core::ops::ControlFlow;

use alloc::{sync::Arc, vec};

use bitflags::bitflags;
use nexus_error::{return_errno_with_message, Errno, Result};
use ostd::{
    cpu::UserContext,
    sync::GuardRwArc,
    task::TaskOptions,
    user::{UserContextApi, UserSpace},
};

use crate::{
    thread::{
        fd_table::FdTable, id, task_future, ThreadFuture, ThreadGroup, ThreadLocalData, ThreadSharedInfo, ThreadState
    },
    vm::ProcessVm,
};

bitflags! {
    /// 支持的 clone 标志
    #[derive(Clone, Copy, Debug)]
    pub struct CloneFlags: u64 {
        const CSIGNAL        = 0x000000ff;
        const CLONE_VM       = 0x00000100;
        const CLONE_FS       = 0x00000200;
        const CLONE_FILES    = 0x00000400;
        const CLONE_SIGHAND  = 0x00000800;
        const CLONE_PARENT   = 0x00008000;
        const CLONE_THREAD   = 0x00010000;
        const CLONE_SETTLS   = 0x00080000;
        const PARENT_SETTID  = 0x00100000;
        const CHILD_CLEARTID = 0x00200000;
        const CHILD_SETTID   = 0x01000000;
    }
}

/// clone 入口：由 syscall 调起  
/// 返回父进程视角下的新 tid；子线程/进程在返回点得 0。  
pub async fn do_clone(parent: &mut ThreadState, uc: &mut UserContext) -> Result<ControlFlow<i32, Option<isize>>> {
    let [raw_flags, child_stack, tls, _parent_tidptr, _child_tidptr, _] = uc.syscall_arguments();
    let flags = CloneFlags::from_bits_truncate(raw_flags as u64);

    // 基本合法性校验
    if flags.contains(CloneFlags::CLONE_SIGHAND) && !flags.contains(CloneFlags::CLONE_VM) {
        return_errno_with_message!(Errno::EINVAL, "CLONE_SIGHAND 需要 CLONE_VM");
    }
    if flags.contains(CloneFlags::CLONE_THREAD)
        && !flags.contains(CloneFlags::CLONE_SIGHAND | CloneFlags::CLONE_VM)
    {
        return_errno_with_message!(
            Errno::EINVAL,
            "CLONE_THREAD 需要同时包含 CLONE_SIGHAND | CLONE_VM"
        );
    }

    // 分治逻辑
    let new_tid = if flags.contains(CloneFlags::CLONE_THREAD) {
        clone_thread(parent, uc, flags, child_stack, tls).await?
    } else {
        clone_process(parent, uc, flags, child_stack, tls).await?
    };

    // 父进程返回 new_tid；子在自身上下文里已置 0
    uc.set_syscall_return_value(new_tid as _);
    Ok(ControlFlow::Continue(Some(new_tid as isize)))
}

// 线程克隆
async fn clone_thread(
    parent: &mut ThreadState,
    uc: &mut UserContext,
    flags: CloneFlags,  
    child_stack: usize,
    tls: usize,
) -> Result<u64> {
    // 与父线程同属线程组 / 地址空间 / 进程上下文
    let child_vm = parent.process_vm.clone();
    let tgroup   = parent.thread_group.clone();

    // 根据 CLONE_FILES 决定 FD 表共享或复制
    let child_fd_table = if flags.contains(CloneFlags::CLONE_FILES) {
        parent.fd_table.clone()
    } else {
        parent.fd_table.dup_table().await
    };

    // ThreadSharedInfo 
    let child_shared = Arc::new(ThreadSharedInfo {
        tid: id::alloc(),
        parent: parent.shared_info.parent.clone(),
        children: GuardRwArc::new(vec![]),
        lifecycle: parent.shared_info.lifecycle.clone(),
        cpu_times: parent.shared_info.cpu_times.clone(),
        start_ticks: parent.shared_info.start_ticks,
    });
    tgroup.attach(child_shared.clone());

    spawn_child(
        parent,
        uc,
        child_vm,
        tgroup,
        child_fd_table,
        flags,
        child_stack,
        tls,
        false,
        child_shared,
    )
    .await
}

// 进程克隆
async fn clone_process(
    parent: &mut ThreadState,
    uc: &mut UserContext,
    flags: CloneFlags,
    child_stack: usize,
    tls: usize,
) -> Result<u64> {
    // CLONE_VM => 共享地址空间；否则 fork
    let child_vm = if flags.contains(CloneFlags::CLONE_VM) {
        parent.process_vm.clone()
    } else {
        Arc::new(ProcessVm::fork_from(&parent.process_vm).await?)
    };

    let tid = id::alloc();
    // 创建新的线程组（进程）
    let tgroup_leader_info = Arc::new(ThreadSharedInfo {
        tid,
        parent: Arc::downgrade(&parent.shared_info),
        children: GuardRwArc::new(vec![]),
        lifecycle: parent.shared_info.lifecycle.clone(),
        cpu_times: parent.shared_info.cpu_times.clone(),
        start_ticks: parent.shared_info.start_ticks,
    });
    let tgroup = ThreadGroup::new_leader(tgroup_leader_info);

    // FD 表：CLONE_FILES => 共享；否则深拷贝
    let fd_table = if flags.contains(CloneFlags::CLONE_FILES) {
        parent.fd_table.clone()
    } else {
        parent.fd_table.dup_table().await
    };

    let parent_process = if flags.contains(CloneFlags::CLONE_PARENT) {
        parent.shared_info.parent.clone()
    } else {
        Arc::downgrade(&parent.thread_group.leader())
    };

    let child_shared = Arc::new(ThreadSharedInfo {
        tid,
        parent: parent_process,
        children: GuardRwArc::new(vec![]),
        lifecycle: parent.shared_info.lifecycle.clone(),
        cpu_times: parent.shared_info.cpu_times.clone(),
        start_ticks: parent.shared_info.start_ticks,
    });

    spawn_child(
        parent,
        uc,
        child_vm,
        tgroup,
        fd_table,
        flags,
        child_stack,
        tls,
        true,
        child_shared,
    )
    .await
}

// 公共：真正生成并调度子 Task  
async fn spawn_child(
    // parent_process: Weak<ThreadSharedInfo>,
    parent_thread: &mut ThreadState,
    uc: &mut UserContext,
    child_vm: Arc<ProcessVm>,
    tgroup: Arc<ThreadGroup>,
    fd_table: Arc<FdTable>,
    flags: CloneFlags,
    child_stack: usize,
    tls: usize,
    is_child_process: bool,
    child_shared: Arc<ThreadSharedInfo>,
) -> Result<u64> {
    let new_tid = child_shared.tid;


    // 用户上下文 
    let user_space = parent_thread.task.user_space().unwrap().clone();
    let mut child_uc = uc.clone();
    child_uc.set_syscall_return_value(0); // 子线程/进程得 0
    if child_stack != 0 {
        child_uc.set_stack_pointer(child_stack);
    }
    if flags.contains(CloneFlags::CLONE_SETTLS) {
        child_uc.set_tls_pointer(tls);
    }
    let child_us = Arc::new(UserSpace::new(user_space.vm_space().clone(), child_uc));

    // Task 
    let thread_local = ThreadLocalData {
        process_vm: child_vm.clone(),
    };
    let child_task = Arc::new(
        TaskOptions::new()
            .user_space(Some(child_us))
            .local_data(thread_local)
            .build(),
    );


    let vm_space = child_vm.root_vmar().vm_space().clone();
    // ThreadState 
    let child_ts = ThreadState {
        task: child_task.clone(),
        thread_group: tgroup.clone(),
        process_vm: child_vm,
        shared_info: child_shared.clone(),
        fd_table,
        user_brk: parent_thread.user_brk,
        cwd: parent_thread.cwd.clone(),
        robust_list_head: parent_thread.robust_list_head,
        robust_list_len: parent_thread.robust_list_len,
        sig_mask: parent_thread.sig_mask,
    };

    if is_child_process && let Some(parent_process) = child_shared.parent.upgrade() {
        parent_process.children.write().push(child_shared);
    }

    let future = task_future(child_ts);
    let future = ThreadFuture::new(vm_space, future);

    // 调度 
    child_task.run(future);
    Ok(new_tid)
}

use core::ops::ControlFlow;

use alloc::{ffi::CString, vec::Vec};
use vfs::PathSlice;
use crate::{
    thread::{init_stack::{MAX_ARGV_NUMBER, MAX_ARG_LEN, MAX_ENVP_NUMBER, MAX_ENV_LEN}, loader::load_elf_to_vm, ThreadState}, vm::ProcessVm,
};
use nexus_error::{errno_with_message, return_errno_with_message, Errno, Result};
use ostd::{mm::Vaddr, user::UserContextApi};

pub async fn do_execve(state: &mut ThreadState, uc: &mut ostd::cpu::UserContext) -> Result<ControlFlow<i32, Option<isize>>> {
    let [path_ptr, argv_ptr_ptr, envp_ptr_ptr, ..] = uc.syscall_arguments();
    let mut new_path = state.process_vm
        .read_cstring(path_ptr, 4096)?
        .into_string()
        .map_err(|_| errno_with_message(Errno::EINVAL, "path is not a valid C string"))?;
    let argv = read_cstring_vec(argv_ptr_ptr, MAX_ARGV_NUMBER, MAX_ARG_LEN, &state.process_vm)?;
    let envp = read_cstring_vec(envp_ptr_ptr, MAX_ENVP_NUMBER, MAX_ENV_LEN, &state.process_vm)?;

    let path = PathSlice::new(&new_path)?;
    if !path.is_absolute() {
        new_path = state.cwd.as_slice().join(&new_path)?.to_string();
    }

    let elf_info = load_elf_to_vm(&state.process_vm, &new_path, argv, envp).await?;

    // 切换用户上下文
    uc.set_instruction_pointer(elf_info.entry as _);
    uc.set_stack_pointer(elf_info.user_sp as _);

    // FD_CLOEXEC 处理
    state.fd_table.clear_cloexec_on_exec().await;

    Ok(ControlFlow::Continue(None))
}

fn read_cstring_vec(
    array_ptr: Vaddr,
    max_string_number: usize,
    max_string_len: usize,
    vm: &ProcessVm,
) -> Result<Vec<CString>> {
    let mut res = Vec::new();
    // On Linux, argv pointer and envp pointer can be specified as NULL.
    if array_ptr == 0 {
        return Ok(res);
    }
    let mut read_addr = array_ptr;
    let mut find_null = false;
    for _ in 0..max_string_number {
        let cstring_ptr = vm.read_val::<usize>(read_addr)?;
        read_addr += 8;
        // read a null pointer
        if cstring_ptr == 0 {
            find_null = true;
            break;
        }
        let cstring = vm.read_cstring(cstring_ptr, max_string_len)?;
        res.push(cstring);
    }
    if !find_null {
        return_errno_with_message!(Errno::E2BIG, "Cannot find null pointer in vector");
    }
    Ok(res)
}

