    pub size: u64,               // Vnode的大小 (字节，对于文件和符号链接)
    pub permissions: FileMode,   // 权限位 (例如，类似POSIX的 mode_t 的低位)
    pub timestamps: Timestamps,    // 时间戳信息 (访问、修改、创建、更改)
    pub uid: u32,                // 用户ID (所有者)
    pub gid: u32,                // 组ID (所有者)
