bitflags! {
    /// RISC-V 缺页异常错误码标志
    pub struct PageFaultErrorCode: usize {
        /// 读取访问导致的缺页 (Load Page Fault)
        const READ          = 1 << 0;
        /// 写入访问导致的缺页 (Store/AMO Page Fault)
        const WRITE         = 1 << 1;
        /// 指令执行导致的缺页 (Instruction Page Fault)
        const INSTRUCTION   = 1 << 2;
    }
}

cpu_local_cell! {
    static IS_KERNEL_INTERRUPTED: bool = false;
